    private void limpar() {
        txtEmail.setText("");
        txtSenha.setText("");
        txtEmail.requestFocus();
    }

    private void mostrar() {
        if (jCheckBox1.isSelected()) {
            txtSenha.setEchoChar('\u0000');
        } else if (!jCheckBox1.isSelected()) {
            txtSenha.setEchoChar('\u2022');
        }
    }

